body
{
	padding-right: 0px;
	padding-left: 0px;
	list-style-position: outside;
	background: url(images/background.gif) #e6dccf fixed repeat-y center top;
	padding-bottom: 0px;
	margin: 0px;
	font: small tahoma, "Bitstream Vera Sans" , "Trebuchet MS" , "Lucida Grande" , lucida, helvetica, sans-serif;
	padding-top: 0px;
	list-style-type: square;
}
A.menu
{
	padding-right: 10px;
	padding-left: 10px;
	color: #806640;
	text-decoration: none;
	background-color: #e6dccf;
}
A.menu:hover
{
	padding-right: 10px;
	padding-left: 10px;
	color: #e6dccf;
	text-decoration: none;
	background-color: #BF8630;
}
A.NewsOperation
{
	font-size: xx-small;
	margin-left: 5px;
	color: #BF8630;
	margin-right: 5px;
	text-decoration: none;
}
A.NewsOperation:hover
{
	font-size: xx-small;
	margin-left: 5px;
	color: #E6B873;
	margin-right: 5px;
	text-decoration: none;
}
.Framed
{
	border: #E6DCCF 1px solid;
}
.FramedForm
{
	border-right: #806640 1px solid;
	border-top: #806640 1px solid;
	border-left: #806640 1px solid;
	border-bottom: #806640 1px solid;
	background-color: #e6dccf;
}
.MenuBar
{
	border-top: #806640 1px solid;
	border-bottom: #806640 1px solid;
	background-color: #e6dccf;
}
.Calendar
{
	border-right: #e6b873 1px solid;
	border-top: #e6b873 1px solid;
	border-left: #e6b873 1px solid;
	border-bottom: #e6b873 1px solid;
}
INPUT
{
	border: #806640 1px solid;
}
INPUT.classic
{
	border: none;
}
TEXTAREA
{
	border: #807940 1px solid;
}
INPUT.PostNews
{
	border: #807940 1px solid;
	width: 500px;
}
INPUT.Login
{
	border: #807940 1px solid;
	width: 250px;
}
TEXTAREA.PostNews
{
	border: #807940 1px solid;
	width: 500px;
	height: 300px;
}
TEXTAREA.CommentTA
{
	border: #807940 1px solid;
	width: 450px;
	height: 100px;
}
.NewsDate
{
	border-top: #e6b873 2px solid;
	font-size: xx-small;
	border-bottom: #e6b873 1px solid;
}

.NewsTitle
{
	font-weight: bolder;
	margin-bottom: 5px;
	text-transform: capitalize;
	padding-top: 2px;
}
.NewsShort
{
	padding-left: 5px;
	margin-bottom: 10px;
}
.NewsLong
{
	padding-left: 5px;
	margin-bottom: 10px;
	border-bottom: #e6b873 1px solid;
}
.CommentText
{
	margin-top: 10px;
	margin-bottom: 5px;
}
.CommentAuthor
{
	font-size: xx-small;
	margin-bottom: 10px;
}
.Comment
{
	clear: both;
	border-right: #806640 1px solid;
	padding-right: 5px;
	padding-left: 5px;
	float: none;
	padding-bottom: 5px;
	border-left: #806640 1px solid;
	width: 500px;
	padding-top: 5px;
}
.Calendar
{
	border: solid 1px #E6B873;
}

